import{j as e,L as i}from"./index-ixzp0WJG.js";/* empty css               */const s=()=>e.jsxs("div",{children:[e.jsx(i,{to:"/levels",className:"backButton level-theme-reason",children:"Back"}),e.jsxs("div",{className:"aLevelContainer level-theme-reason",children:[e.jsx("h1",{children:"Reason"}),e.jsx("p",{children:"Intelligence and rationality rise to the forefront when the emotionalism of the lower levels is transcended."}),e.jsx("p",{children:"Reason is capable of handling large, complex amounts of data and making rapid, correct decisions; of understanding the intricacies of relationships, gradations, and fine distinctions; and of expert manipulation of symbols as abstract concepts become increasingly important."}),e.jsx("p",{children:"Understanding of information and logic are the main tools of accomplishment that are the hallmarks of level 400. This is the level of Nobel Prize winners, great statesmen, Supreme Court Justices, Einstein, Freud, and many other important figures in the history of thought."}),e.jsx("p",{children:"The shortcomings of this level are the failure to clearly distinguish the difference between symbols and what they represent, and the confusion between the objective and subjective worlds, which limits the understanding of causality."}),e.jsx("p",{children:'Intellectualising can become an end in itself. Reason is limited in that it does not afford the capacity for the discernment of essence or the "critical point" of a complex issue.'}),e.jsx("p",{children:"Reason is disciplined by the dialectic of logic as a necessity to discern the linear truth of confirmable facts. It produces massive amounts of information and documentation, but it lacks the capacity to resolve discrepancies in data and conclusions."}),e.jsx("p",{children:"Although reason is highly effective in a technical world where the methodologies of logic dominate, reason itself—paradoxically—is the major block to reaching higher levels of consciousness because it attracts identification of the self as mind."}),e.jsx("p",{children:"The mind is satisfied with the acquisition of knowledge but then discovers that alone, it is insufficient to bring about transformation, which requires a further step to convert data into an inner experiential reality."}),e.jsx("p",{children:"The intellect is used to being satisfied by hearing “about” a subject and may naively conclude that the information itself should be sufficient. While this is often partially true, at other times, the transfer from the acquisition of information to subjective experience comes about through spiritual practice, meditation, contemplation, and devotion."}),e.jsx("p",{children:"A major deterrent to transcending identification of the self with mind is the processing of data, symbols, and words via random mentalisation. During meditation, this mental chatter is frustrating and becomes a source of anxiety. To try to silence the mind via willpower is ineffective, and the results are limited and brief. By understanding the source of the flow of mentalisation, it can be transcended."}),e.jsx("p",{children:"Mentalisation is of egocentric origin, and its primary function is commentary. Unless requested, thought is a vanity—an endless procession of opinion, rationalisation, reprocessing, evaluating, and subtle judgment by which thoughts are given value or importance via presumed significance, simply because they are “mine.”"}),e.jsx("p",{children:"The “importance” of thoughts is a self-appointed vanity. The ego presumes that it has the “right” to intrude upon peace and silence with endless chatter. The mind has an imaginary audience and carries on a monologue for self-audition. The undisciplined mind has an observation commentary or opinion on everything."}),e.jsx("p",{children:"It is a relief to let the mind become silent and just “be” with surroundings. Peace results. In order to realise that a running commentary is not necessary—or even authorised—the will gives the mind permission to be silent."})]})]});export{s as default};
